add_action( 'rest_api_init', function () {
    register_rest_route( 'wpbp/v1', '/status', array(
        'methods'             => WP_REST_Server::READABLE,
        'permission_callback' => '__return_true',
        'callback'            => function () {
            return rest_ensure_response( array( 'status' => 'ok', 'timestamp' => time() ) );
        },
    ) );
} );

add_action( 'rest_api_init', function () {
    register_rest_route( 'wpbp/v1', '/books/(?P<id>\d+)', array(
        'methods'             => WP_REST_Server::READABLE,
        'permission_callback' => '__return_true',
        'callback'            => fn( WP_REST_Request $request ) => array( 'id' => absint( $request['id'] ) ),
        'args'                => array( 'id' => array( 'validate_callback' => fn( $value ) => is_numeric( $value ) ) ),
    ) );
} );

add_action( 'rest_api_init', function () {
    register_rest_route( 'wpbp/v1', '/private', array(
        'methods'             => 'GET',
        'permission_callback' => fn() => current_user_can( 'manage_options' ),
        'callback'            => fn() => array( 'secret' => true ),
    ) );
} );

add_action( 'rest_api_init', function () {
    register_rest_route( 'wpbp/v1', '/options', array(
        'methods'             => WP_REST_Server::CREATABLE,
        'permission_callback' => '__return_true',
        'args'                => array( 'title' => array( 'sanitize_callback' => 'sanitize_text_field' ) ),
        'callback'            => fn( WP_REST_Request $request ) => array( 'title' => $request->get_param( 'title' ) ),
    ) );
} );
